#!/usr/bin/env node
// scripts/regen-coverage-roadmap.mjs
//
// Reads coverage/coverage-summary.json and prepends an auto-generated
// "Live numbers" section to docs/COVERAGE_ROADMAP.md (between two
// HTML markers so it can be regenerated idempotently). The historical
// phase narrative below the markers is left intact.
//
// Markers:
//   <!-- LIVE_NUMBERS_START -->
//   ...auto-generated block...
//   <!-- LIVE_NUMBERS_END -->
//
// Idempotent: if the markers are missing it inserts them at the top
// (right after the H1). On subsequent runs it replaces the block in
// place.

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, '..');
const ROADMAP = resolve(REPO_ROOT, 'docs/COVERAGE_ROADMAP.md');
const SUMMARY = resolve(REPO_ROOT, 'coverage/coverage-summary.json');

if (!existsSync(SUMMARY)) {
  console.error('coverage-summary.json missing — run `npm run test:coverage` first.');
  process.exit(2);
}
if (!existsSync(ROADMAP)) {
  console.error('docs/COVERAGE_ROADMAP.md missing.');
  process.exit(2);
}

const total = JSON.parse(readFileSync(SUMMARY, 'utf8')).total;
const ts = new Date().toISOString();

const block = `<!-- LIVE_NUMBERS_START -->
## Live coverage numbers

> _Auto-regenerated by [\`scripts/regen-coverage-roadmap.mjs\`](../scripts/regen-coverage-roadmap.mjs).
> Last regenerated: \`${ts}\`._

| Metric | Actual | CI floor (in \`vitest.config.ts\`) |
|---|---:|---:|
| Lines | **${total.lines.pct.toFixed(2)}%** | _see thresholds_ |
| Branches | **${total.branches.pct.toFixed(2)}%** | _see thresholds_ |
| Functions | **${total.functions.pct.toFixed(2)}%** | _see thresholds_ |
| Statements | **${total.statements.pct.toFixed(2)}%** | _see thresholds_ |

The floor is ratcheted nightly by [\`scripts/ratchet-coverage-thresholds.mjs\`](../scripts/ratchet-coverage-thresholds.mjs).
<!-- LIVE_NUMBERS_END -->`;

let md = readFileSync(ROADMAP, 'utf8');
const startRe = /<!-- LIVE_NUMBERS_START -->[\s\S]*?<!-- LIVE_NUMBERS_END -->/;
if (startRe.test(md)) {
  md = md.replace(startRe, block);
} else {
  // Insert right after the first H1 line
  md = md.replace(/^(#\s+.*?\n)/, `$1\n${block}\n`);
}
writeFileSync(ROADMAP, md, 'utf8');
console.log(`Updated ${ROADMAP}`);
